VALUES
  ('colonel-d0d1b9a2-moex-00048', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '假設無任何永久性差異或暫時性差異發生，甲公司X4年淨損失$2,800,000 ，其他各年度淨利如下表，假設規定損失可先前抵 2 年，再後抵 20 年， 則X4年底之所得稅利益為何？ X1年 X2年 X3年 X4年 X5年 X6年 課稅所得 $720,000 $680,000 $600,000 $(2,800,000) $560,000 $2,320,000 稅率 20% 22% 24% 26% 28% 30%', '["$293,600", "$444,800", "$738,400", "$728,000 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00049', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司以成本$40,000，累計折舊$30,000之舊機器，交換乙公司一台公允價 值$50,000，預期耐用年限20年之新機器。交換時甲公司需支付乙公司現金 $43,000。若此交換具商業實質，則甲公司應記錄新機器之取得成本為：', '["$40,000", "$47,000", "$50,000", "$53,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00050', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '下列為甲公司X1年度資訊： 銷貨成本 $226,000 1月1日商品存貨 54,800 12月31日商品存貨 57,400 1月1日應付帳款 54,400 12月31日應付帳款 59,800 試問存貨付現數為何？', '["$218,000", "$228,800", "$223,200", "$234,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00051', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '在物價上漲期間，若公司將存貨計算方法由先進先出法改為加權平均法， 則：', '["流動比率減少", "存貨週轉率減少", "負債對權益比率減少", "現金流量減少"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00052', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '於現金股利發放日，收到採用權益法會計處理之關聯企業投資發放的現金 股利時，投資公司應作什麼處理？', '["貸：採用權益法之關聯企業損益之份額", "貸：股利收入", "貸：採用權益法之關聯企業投資", "貸：應收股利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00053', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司所有存貨於5月1日的土石流中全數損毀，由於尚未完成4月份之 財務報表，因此必須估計期末存貨損失金額。該公司 4 月期初存貨為 $215,450，4月份進貨$192,530，銷貨收入$542,500。假設公司之平均毛利 率為40%，試問損毀之存貨金額估計應為：', '["$81,480", "$82,480", "$87,480", "$217,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00054', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於 X1 年 9 月 1 日以$75,000 購得機器一台，估計殘值$10,000，耐 用年限4年，並使用雙倍餘額遞減法提列折舊。在X3年12月31日時， 以$13,000出售該機器。試問出售分錄應包括：', '["借記：「出售損失」$542", "借記：「出售損失」$2,625", "借記：「出售損失」$2,667", "貸記：「出售利得」$13,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00055', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司X0年1月1日有面額$1,000，240,000股之普通股股本$240,000,000 ，股本溢價-普通股$354,000,000。保留盈餘$972,000,000。X0年3月1日， 公司以$66,000,000購回30,000股庫藏股。4月1日出售15,000股庫藏股， 得款$34,500,000。5 月 1 日再出售 15,000 股庫藏股，得款$30,000,000，試 問甲公司X0年12月31日應於財務報表顯示之帳面金額，何者正確？', '["股本溢價總額 $352,500,000（貸餘）", "股本溢價-庫藏股 $1,500,000（借餘）", "保留盈餘 $970,500,000（貸餘）", "庫藏股交易損失 $1,500,000（借餘） 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00056', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X1年1 月1 日發行5年期公司債，面額$500,000，票面利率10% ，每年 1 月 1 日及 7 月 1 日付息，當時有效利率 8%。X1 年 7 月 1 日付 息分錄借記「公司債利息」$21,622 及「公司債溢價」$3,378，則該公司 債售價為：', '["$500,000", "$533,780", "$540,550", "$560,720"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00057', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司從事成衣進口買賣，X1 年 12 月 31 日之期末存貨帳帳載餘額原有 $412,000，發現尚有額外資訊如下： ⑴期末存貨帳帳載餘額$412,000中，包括一筆寄銷品$72,000，甲公司為寄 銷人。 ⑵期末存貨帳帳載餘額$412,000中，包括存放於倉庫中之「辦公用品」存 貨$22,000，可供公司管理人員在次年度辦公使用。 ⑶期末存貨帳帳載餘額$412,000中，未包括一筆12月28日目的地交貨， 價值$48,000之進貨。甲公司直到X2年1月2日才收到該筆進貨。 ⑷期末存貨帳帳載餘額$412,000中，包括一筆已受損但尚未記錄減損之存 貨，其原始成本為$38,000，淨變現價值為$10,000。 ⑸期末存貨帳帳載餘額$412,000中，包括一筆承銷品$43,000，甲公司為承 銷人。 試問甲公司 X1 年12 月31 日財務狀況表所列，期末存貨之正確餘額（淨 額）應為：', '["$319,000", "$341,000", "$369,000", "$460,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
